head.b:skin:
/* ─── 기본 초기화 ─── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
body {
  font-family: 'Apple SD Gothic Neo', 'Noto Sans KR', 'Segoe UI', sans-serif;
  background: #fffaf7;
  color: #2d2d2d;
  font-size: 16px;
  line-height: 1.7;
}
a { color: inherit; text-decoration: none; }
img { max-width: 100%; height: auto; display: block; }

/* ─── 헤더 ─── */
#header-wrap {
  background: #ffffff;
  color: #2d2d2d;
  padding: 0;
  position: sticky;
  top: 0;
  z-index: 100;
  box-shadow: 0 2px 12px rgba(0,0,0,.08);
  border-bottom: 3px solid #ff6b35;
}
#header-inner {
  max-width: 1100px;
  margin: 0 auto;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 20px;
  height: 60px;
}
#header-inner h1 a {
  font-size: 1.4rem;
  font-weight: 700;
  color: #ff6b35;
  letter-spacing: -0.5px;
}
.header-nav {
  display: flex;
  gap: 20px;
  list-style: none;
}
.header-nav a {
  color: #555;
  font-size: .9rem;
  transition: color .2s;
  font-weight: 500;
}
.header-nav a:hover { color: #ff6b35; }

/* ─── 히어로 배너 (홈만) ─── */
.hero-banner {
  background: linear-gradient(135deg, #ff6b35 0%, #f7931e 50%, #ffc045 100%);
  color: #fff;
  text-align: center;
  padding: 70px 20px;
}
.hero-banner h2 {
  font-size: 2.2rem;
  margin-bottom: 12px;
  text-shadow: 0 2px 8px rgba(0,0,0,.15);
}
.hero-banner p {
  font-size: 1.1rem;
  opacity: .92;
  max-width: 520px;
  margin: 0 auto;
}

/* ─── 레이아웃 래퍼 ─── */
#main-wrap {
  max-width: 1100px;
  margin: 40px auto;
  padding: 0 20px;
  display: grid;
  grid-template-columns: 1fr 300px;
  gap: 30px;
}
@media (max-width: 768px) {
  #main-wrap { grid-template-columns: 1fr; }
}

/* ─── 포스트 그리드 ─── */
#content { min-width: 0; }
.blog-posts {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 24px;
}
@media (max-width: 600px) {
  .blog-posts { grid-template-columns: 1fr; }
}

/* ─── 포스트 카드 ─── */
.post-card {
  background: #fff;
  border-radius: 16px;
  overflow: hidden;
  box-shadow: 0 2px 16px rgba(255,107,53,.08);
  transition: transform .2s, box-shadow .2s;
}
.post-card:hover {
  transform: translateY(-5px);
  box-shadow: 0 12px 28px rgba(255,107,53,.15);
}
.post-card-thumb {
  width: 100%;
  height: 200px;
  object-fit: cover;
}
.post-card-thumb-placeholder {
  width: 100%;
  height: 200px;
  background: linear-gradient(135deg, #ffe0d0, #ffd0a0);
  display: flex;
  align-items: center;
  justify-content: center;
  color: #ff6b35;
  font-size: 2.5rem;
}
.post-card-body { padding: 16px; }
.post-card-labels {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
  margin-bottom: 8px;
}
.post-card-label {
  background: #fff3ee;
  color: #ff6b35;
  font-size: .75rem;
  padding: 2px 10px;
  border-radius: 12px;
  font-weight: 600;
}
.post-card-title {
  font-size: 1rem;
  font-weight: 700;
  line-height: 1.4;
  margin-bottom: 8px;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
}
.post-card-title a:hover { color: #ff6b35; }
.post-card-snippet {
  font-size: .85rem;
  color: #777;
  display: -webkit-box;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  overflow: hidden;
  margin-bottom: 12px;
}
.post-card-meta {
  font-size: .78rem;
  color: #aaa;
}

/* ─── 사이드바 ─── */
#sidebar { min-width: 0; }
.sidebar-widget {
  background: #fff;
  border-radius: 16px;
  padding: 20px;
  margin-bottom: 24px;
  box-shadow: 0 2px 16px rgba(255,107,53,.08);
}
.sidebar-widget-title {
  font-size: 1rem;
  font-weight: 700;
  margin-bottom: 14px;
  padding-bottom: 10px;
  border-bottom: 2px solid #ff6b35;
  color: #2d2d2d;
}

/* ─── 글 상세 페이지 ─── */
.post-detail {
  background: #fff;
  border-radius: 16px;
  padding: 32px;
  box-shadow: 0 2px 16px rgba(255,107,53,.08);
}
.post-detail h1 {
  font-size: 1.7rem;
  line-height: 1.35;
  margin-bottom: 12px;
}
.post-detail-meta {
  font-size: .85rem;
  color: #aaa;
  margin-bottom: 24px;
  padding-bottom: 16px;
  border-bottom: 1px solid #f0ebe6;
}
.post-detail-body { font-size: 1rem; line-height: 1.9; }
.post-detail-body h2 {
  font-size: 1.35rem;
  margin: 36px 0 12px;
  padding-left: 12px;
  border-left: 4px solid #ff6b35;
  color: #2d2d2d;
}
.post-detail-body h3 {
  font-size: 1.1rem;
  margin: 24px 0 8px;
  color: #444;
}
.post-detail-body p { margin-bottom: 14px; }
.post-detail-body ul, .post-detail-body ol {
  padding-left: 20px;
  margin-bottom: 14px;
}
.post-detail-body li { margin-bottom: 6px; }
.post-detail-body table {
  width: 100%;
  border-collapse: collapse;
  margin: 20px 0;
  font-size: .9rem;
}
.post-detail-body td, .post-detail-body th {
  border: 1px solid #f0e8e0;
  padding: 10px 12px;
  text-align: left;
}
.post-detail-body th { background: #fff8f5; font-weight: 600; color: #ff6b35; }
.post-detail-body blockquote {
  background: #fff8f5;
  border-left: 4px solid #ff6b35;
  padding: 14px 18px;
  margin: 20px 0;
  border-radius: 0 8px 8px 0;
  color: #555;
}
.post-detail-body img {
  max-width: 100%;
  border-radius: 10px;
  margin: 16px auto;
}

/* ─── 페이지네이션 ─── */
.blog-pager {
  display: flex;
  justify-content: space-between;
  margin-top: 32px;
  gap: 12px;
}
.blog-pager a {
  background: #ff6b35;
  color: #fff;
  padding: 10px 22px;
  border-radius: 25px;
  font-size: .9rem;
  font-weight: 600;
  transition: background .2s, transform .2s;
}
.blog-pager a:hover { background: #e55a25; transform: translateY(-2px); }

/* ─── 푸터 ─── */
#footer-wrap {
  background: #fff3ee;
  color: #999;
  text-align: center;
  padding: 30px 20px;
  font-size: .85rem;
  margin-top: 60px;
  border-top: 2px solid #ffd5c0;
}
#footer-wrap a { color: #ff6b35; }

/* ─── 라벨 페이지 ─── */
.label-list { list-style: none; }
.label-list li {
  padding: 8px 0;
  border-bottom: 1px solid #f9f0eb;
  display: flex;
  justify-content: space-between;
  font-size: .9rem;
}
.label-list li:last-child { border-bottom: none; }
.label-list a:hover { color: #ff6b35; }
